// ─── PLACE OF SERVICE CODES ────────────────────────────────────────────────────
const POS_CODES: { code: string; description: string; notes: string }[] = [
  { code: "01", description: "Pharmacy", notes: "A facility or location where drugs and other medically related items and services are sold, dispensed, or otherwise provided directly to patients" },
  { code: "02", description: "Telehealth Provided Other than in Patient's Home", notes: "The location where health services and health related services are provided or received, through telecommunication technology. Patient is not located in their home when receiving health services or health related services through telecommunication technology" },
  { code: "03", description: "School", notes: "A facility whose primary purpose is education" },
  { code: "04", description: "Homeless Shelter", notes: "A facility or location whose primary purpose is to provide temporary housing to homeless individuals" },
  { code: "05", description: "Indian Health Service Free-Standing Facility", notes: "A facility or location, owned and operated by the Indian Health Service, which provides diagnostic, therapeutic (surgical and non-surgical), and rehabilitation services to American Indians and Alaska Natives who do not require hospitalization" },
  { code: "06", description: "Indian Health Service Provider-Based Facility", notes: "A facility or location, owned and operated by the Indian Health Service, which provides diagnostic, therapeutic (surgical and non-surgical), and rehabilitation services rendered by, or under the supervision of, physicians to American Indians and Alaska Natives admitted as inpatients or outpatients" },
  { code: "07", description: "Tribal 638 Free-Standing Facility", notes: "A facility or location owned and operated by a federally recognized American Indian or Alaska Native tribe or tribal organization under a 638 agreement, which provides diagnostic, therapeutic (surgical and non-surgical), and rehabilitation services to tribal members who do not require hospitalization" },
  { code: "08", description: "Tribal 638 Provider-Based Facility", notes: "A facility or location owned and operated by a federally recognized American Indian or Alaska Native tribe or tribal organization under a 638 agreement, which provides diagnostic, therapeutic (surgical and non-surgical), and rehabilitation services to tribal members admitted as inpatients or outpatients" },
  { code: "09", description: "Prison/Correctional Facility", notes: "A prison, jail, reformatory, work farm, detention center, or any other similar facility maintained by either Federal, State or local authorities for the purpose of confinement or rehabilitation of adult or juvenile criminal offenders" },
  { code: "10", description: "Telehealth Provided in Patient's Home", notes: "The location where health services and health related services are provided or received, through telecommunication technology. Patient is located in their home (which is a location other than a hospital or other facility) when receiving health services or health related services through telecommunication technology" },
  { code: "11", description: "Office", notes: "Location, other than a hospital, skilled nursing facility (SNF), military treatment facility, community health center, State or local public health clinic, or intermediate care facility (ICF), where the health professional routinely provides health examinations, diagnosis, and treatment of illness or injury on an ambulatory basis" },
  { code: "12", description: "Home", notes: "Location, other than a hospital or other facility, where the patient receives care in a private residence" },
  { code: "13", description: "Assisted Living Facility", notes: "Congregate residential facility with self-contained living units providing assessment of each resident's needs and on-site support 24 hours a day, 7 days a week, with the capacity to deliver or arrange for services including some health care and other services" },
  { code: "14", description: "Group Home", notes: "A residence, with shared living areas, where clients receive supervision and other services such as social and/or behavioral services, custodial service, and minimal services (e.g., medication administration)" },
  { code: "15", description: "Mobile Unit", notes: "A facility/unit that moves from place-to-place equipped to provide preventive, screening, diagnostic, and/or treatment services" },
  { code: "16", description: "Temporary Lodging", notes: "A short term accommodation such as a hotel, camp ground, hostel, cruise ship or resort where the patient receives care, and which is not identified by any other POS code" },
  { code: "17", description: "Walk-in Retail Health Clinic", notes: "A walk-in health clinic, other than an office, urgent care facility, pharmacy or independent clinic and not described by any other Place of Service code, that is located within a retail operation and provides, on an ambulatory basis, preventive and primary care services" },
  { code: "18", description: "Place of Employment-Worksite", notes: "A location, not described by any other POS code, owned or operated by a public or private entity where the patient is employed, and where a health professional provides on-going or episodic occupational medical, therapeutic or rehabilitative services to the individual" },
  { code: "19", description: "Off Campus-Outpatient Hospital", notes: "A portion of an off-campus hospital provider based department which provides diagnostic, therapeutic (both surgical and nonsurgical), and rehabilitation services to sick or injured persons who do not require hospitalization or institutionalization" },
  { code: "20", description: "Urgent Care Facility", notes: "Location, distinct from a hospital emergency room, an office, or a clinic, whose purpose is to diagnose and treat illness or injury for unscheduled, ambulatory patients seeking immediate medical attention" },
  { code: "21", description: "Inpatient Hospital", notes: "A facility, other than psychiatric, which primarily provides diagnostic, therapeutic (both surgical and nonsurgical), and rehabilitation services by, or under, the supervision of physicians to patients admitted for a variety of medical conditions" },
  { code: "22", description: "On Campus-Outpatient Hospital", notes: "A portion of a hospital's main campus which provides diagnostic, therapeutic (both surgical and nonsurgical), and rehabilitation services to sick or injured persons who do not require hospitalization or institutionalization" },
  { code: "23", description: "Emergency Room – Hospital", notes: "A portion of a hospital where emergency diagnosis and treatment of illness or injury is provided" },
  { code: "24", description: "Ambulatory Surgical Center", notes: "A freestanding facility, other than a physician's office, where surgical and diagnostic services are provided on an ambulatory basis" },
  { code: "25", description: "Birthing Center", notes: "A facility, other than a hospital's maternity facilities or a physician's office, which provides a setting for labor, delivery, and immediate post-partum care as well as immediate care of new born infants" },
  { code: "26", description: "Military Treatment Facility", notes: "A medical facility operated by one or more of the Uniformed Services. Military Treatment Facility (MTF) also refers to certain former military facilities of the Uniformed Services" },
  { code: "27", description: "Outreach Site/Street", notes: "A non-permanent location on the street or found environment, not described by any other POS code, where health professionals provide preventive, screening, diagnostic, and/or treatment services to unsheltered homeless individuals" },
  { code: "28", description: "Telehealth Provided in Provider's Office", notes: "The location where health services and health related services are provided or received, through a telecommunication system. The rendering provider is located in the office" },
  { code: "31", description: "Skilled Nursing Facility", notes: "A facility which primarily provides inpatient skilled nursing care and related services to patients who require medical, nursing, or rehabilitative services but does not provide the level of care or treatment available in a hospital" },
  { code: "32", description: "Nursing Facility", notes: "A facility which primarily provides to residents skilled nursing care and related services for the rehabilitation of injured, disabled, or sick persons, or, on a regular basis, health-related care services above the level of custodial care to other than mentally retarded individuals" },
  { code: "33", description: "Custodial Care Facility", notes: "A facility which provides room, board and other personal assistance services, generally on a long-term basis, and which does not include a medical component" },
  { code: "34", description: "Hospice", notes: "A facility, other than a patient's home, in which palliative and supportive care for terminally ill patients and their families are provided" },
  { code: "41", description: "Ambulance – Land", notes: "A land vehicle specifically designed, equipped and staffed for lifesaving and transporting the sick or injured" },
  { code: "42", description: "Ambulance – Air or Water", notes: "An air or water vehicle specifically designed, equipped and staffed for lifesaving and transporting the sick or injured" },
  { code: "49", description: "Independent Clinic", notes: "A location, not part of a hospital and not described by any other Place of Service code, that is organized and operated to provide preventive, diagnostic, therapeutic, rehabilitative, or palliative services to outpatients only" },
  { code: "50", description: "Federally Qualified Health Center", notes: "A facility located in a medically underserved area that provides Medicare beneficiaries preventive primary medical care under the general direction of a physician" },
  { code: "51", description: "Inpatient Psychiatric Facility", notes: "A facility that provides inpatient psychiatric services for the diagnosis and treatment of mental illness on a 24-hour basis, by or under the supervision of a physician" },
  { code: "52", description: "Psychiatric Facility-Partial Hospitalization", notes: "A facility for the diagnosis and treatment of mental illness that provides a planned therapeutic program for patients who do not require full time hospitalization, but who need broader programs than are possible from outpatient visits to a hospital-based or hospital-affiliated facility" },
  { code: "53", description: "Community Mental Health Center", notes: "A facility that provides the following services: outpatient services, including specialized outpatient services for children, the elderly, individuals who are chronically ill, and residents of the CMHC's mental health services area who have been discharged from inpatient treatment at a mental health facility; 24 hour a day emergency care services; day treatment, other partial hospitalization services, or psychosocial rehabilitation services; screening for patients being considered for admission to State mental health facilities to determine the appropriateness of such admission; and consultation and education services" },
  { code: "54", description: "Intermediate Care Facility/Individuals with Intellectual Disabilities", notes: "A facility which primarily provides health-related care and services above the level of custodial care to intellectually disabled individuals but does not provide the level of care or treatment available in a hospital or SNF" },
  { code: "55", description: "Residential Substance Abuse Treatment Facility", notes: "A facility which provides treatment for substance (alcohol and drug) abuse to live-in residents who do not require acute medical care. Services include individual and group therapy and counseling, family counseling, laboratory tests, drugs and supplies, psychological testing, and room and board" },
  { code: "56", description: "Psychiatric Residential Treatment Center", notes: "A facility or distinct part of a facility for psychiatric care which provides a total 24-hour therapeutically planned and professionally staffed group living and learning environment" },
  { code: "57", description: "Non-residential Substance Abuse Treatment Facility", notes: "A location which provides treatment for substance (alcohol and drug) abuse on an ambulatory basis. Services include individual and group therapy and counseling, family counseling, laboratory tests, drugs and supplies, and psychological testing" },
  { code: "58", description: "Non-residential Opioid Treatment Facility", notes: "A location that provides treatment for opioid use disorder on an ambulatory basis. Services include methadone and other forms of Medication Assisted Treatment (MAT)" },
  { code: "60", description: "Mass Immunization Center", notes: "A location where providers administer pneumococcal pneumonia and influenza virus vaccinations and submit these services as electronic media claims, paper claims, or using the roster billing method. This generally takes place in a mass immunization setting, such as a public health center, pharmacy, or mall but may include a physician office setting" },
  { code: "61", description: "Comprehensive Inpatient Rehabilitation Facility", notes: "A facility that provides comprehensive rehabilitation services under the supervision of a physician to inpatients with physical disabilities. Services include physical therapy, occupational therapy, speech pathology, social or psychological services, and orthotics and prosthetics services" },
  { code: "62", description: "Comprehensive Outpatient Rehabilitation Facility", notes: "A facility that provides comprehensive rehabilitation services under the supervision of a physician to outpatients with physical disabilities. Services include physical therapy, occupational therapy, and speech pathology services" },
  { code: "65", description: "End-Stage Renal Disease Treatment Facility", notes: "A facility other than a hospital, which provides dialysis treatment, maintenance, and/or training to patients or caregivers on an ambulatory or home-care basis" },
  { code: "66", description: "Programs of All-inclusive Care for the Elderly (PACE) Center", notes: "A program that provides the following services: outpatient services such as primary care and geriatric assessments; recreational therapy, occupational therapy, physical therapy, and speech therapy; nutritional counseling; social services; personal care and supportive services; non-emergency medical transportation" },
  { code: "71", description: "State or Local Public Health Clinic", notes: "A facility maintained by either State or local health departments that provides ambulatory primary medical care under the general direction of a physician" },
  { code: "72", description: "Rural Health Clinic", notes: "A certified facility which is located in a rural medically underserved area that provides ambulatory primary medical care under the general direction of a physician" },
  { code: "81", description: "Independent Laboratory", notes: "A laboratory certified in accordance with the Clinical Laboratory Improvement Amendments (CLIA) Title XIII to perform diagnostic and/or clinical tests independent of an institution or a physician's office" },
  { code: "99", description: "Other Place of Service", notes: "Other place of service not identified above" },
];

