// ─── MAIN SEED FUNCTION ────────────────────────────────────────────────────────
export async function seedReferenceTables(pool: Pool): Promise<void> {
  try {
    // ── CARC codes table ────────────────────────────────────────────────────
    await pool.query(`
      CREATE TABLE IF NOT EXISTS carc_codes (
        id SERIAL PRIMARY KEY,
        code VARCHAR(10) NOT NULL UNIQUE,
        description TEXT NOT NULL,
        group_codes VARCHAR(50) NOT NULL DEFAULT 'CO'
      )
    `);
    const { rows: carcCount } = await pool.query("SELECT COUNT(*) FROM carc_codes");
    if (parseInt(carcCount[0].count) === 0) {
      for (const c of CARC_CODES) {
        await pool.query(
          "INSERT INTO carc_codes (code, description, group_codes) VALUES ($1, $2, $3) ON CONFLICT (code) DO NOTHING",
          [c.code, c.description, c.group_codes]
        );
      }
      console.log(`Seeded ${CARC_CODES.length} CARC codes`);
    }

    // ── RARC codes table ────────────────────────────────────────────────────
    await pool.query(`
      CREATE TABLE IF NOT EXISTS rarc_codes (
        id SERIAL PRIMARY KEY,
        code VARCHAR(10) NOT NULL UNIQUE,
        description TEXT NOT NULL,
        type VARCHAR(20) NOT NULL DEFAULT 'informational'
      )
    `);
    const { rows: rarcCount } = await pool.query("SELECT COUNT(*) FROM rarc_codes");
    if (parseInt(rarcCount[0].count) === 0) {
      for (const r of RARC_CODES) {
        await pool.query(
          "INSERT INTO rarc_codes (code, description, type) VALUES ($1, $2, $3) ON CONFLICT (code) DO NOTHING",
          [r.code, r.description, r.type]
        );
      }
      console.log(`Seeded ${RARC_CODES.length} RARC codes`);
    }

    // ── Place of Service codes table ─────────────────────────────────────────
    await pool.query(`
      CREATE TABLE IF NOT EXISTS pos_codes (
        id SERIAL PRIMARY KEY,
        code VARCHAR(2) NOT NULL UNIQUE,
        description VARCHAR(200) NOT NULL,
        notes TEXT
      )
    `);
    const { rows: posCount } = await pool.query("SELECT COUNT(*) FROM pos_codes");
    if (parseInt(posCount[0].count) === 0) {
      for (const p of POS_CODES) {
        await pool.query(
          "INSERT INTO pos_codes (code, description, notes) VALUES ($1, $2, $3) ON CONFLICT (code) DO NOTHING",
          [p.code, p.description, p.notes]
        );
      }
      console.log(`Seeded ${POS_CODES.length} Place of Service codes`);
    }

    // ── Taxonomy codes table ─────────────────────────────────────────────────
    await pool.query(`
      CREATE TABLE IF NOT EXISTS taxonomy_codes (
        id SERIAL PRIMARY KEY,
        code VARCHAR(20) NOT NULL UNIQUE,
        display TEXT NOT NULL,
        category VARCHAR(100) NOT NULL DEFAULT 'Other'
      )
    `);
    const { rows: taxCount } = await pool.query("SELECT COUNT(*) FROM taxonomy_codes");
    if (parseInt(taxCount[0].count) < 100) {
      for (const t of TAXONOMY_CODES) {
        await pool.query(
          "INSERT INTO taxonomy_codes (code, display, category) VALUES ($1, $2, $3) ON CONFLICT (code) DO UPDATE SET display = EXCLUDED.display, category = EXCLUDED.category",
          [t.code, t.display, t.category]
        );
      }
      console.log(`Seeded/updated ${TAXONOMY_CODES.length} taxonomy codes`);
    }

    // ── Additional payers ────────────────────────────────────────────────────
    let payerInserted = 0;
    for (const p of ADDITIONAL_PAYERS) {
      const existing = await pool.query("SELECT id FROM payers WHERE LOWER(name) = LOWER($1)", [p.name]);
      if (existing.rows.length === 0) {
        await pool.query(
          `INSERT INTO payers (id, name, payer_id, timely_filing_days, auth_required, billing_type, is_active, is_custom)
           VALUES (gen_random_uuid()::text, $1, $2, $3, $4, 'professional', true, false)`,
          [p.name, p.payerId, p.timelyFilingDays, p.authRequired]
        );
        payerInserted++;
      }
    }
    if (payerInserted > 0) {
      console.log(`Added ${payerInserted} new payers to the payer database`);
    }

  } catch (err: any) {
    console.error("Reference table seed error:", err?.message || err);
  }
}
